import { auth } from "@/auth";
import { redirect } from "next/navigation";
import DashboardLayout from "@/app/components/DashboardLayout";
import { prisma } from "@/lib/prisma";
import Link from "next/link";
import CompanyVerifyButton from "@/app/components/CompanyVerifyButton";

export default async function AdminCompaniesPage() {
    const session = await auth();
    if (!session?.user || session.user.role !== "ADMIN") redirect("/login");

    const companies = await prisma.company.findMany({
        include: { _count: { select: { jobs: true } } },
        orderBy: { createdAt: "desc" },
    });

    return (
        <DashboardLayout role="ADMIN" userName={session.user.name || "Admin"}>
            <div style={{ padding: "2rem" }}>
                <div style={{ marginBottom: "2rem" }}>
                    <h1 style={{ fontSize: "1.5rem", fontWeight: 800, color: "var(--text)", marginBottom: "0.25rem" }}>
                        Quản lý công ty
                    </h1>
                    <p style={{ color: "var(--text-muted)" }}>Hệ thống đang có {companies.length} công ty.</p>
                </div>

                <div className="card" style={{ overflow: "hidden", padding: 0 }}>
                    <table style={{ width: "100%", borderCollapse: "collapse" }}>
                        <thead>
                            <tr style={{ borderBottom: "1.5px solid var(--border)", background: "var(--bg-card)" }}>
                                <th style={thStyle}>Công ty</th>
                                <th style={thStyle}>Ngành nghề</th>
                                <th style={thStyle}>Việc làm</th>
                                <th style={thStyle}>Trạng thái</th>
                                <th style={{ ...thStyle, textAlign: "right" }}>Thao tác</th>
                            </tr>
                        </thead>
                        <tbody>
                            {companies.map((company) => (
                                <tr key={company.id} style={{ borderBottom: "1px solid var(--border)" }}>
                                    <td style={tdStyle}>
                                        <div style={{ fontWeight: 600, color: "var(--text)", fontSize: "0.9375rem" }}>
                                            <Link href={`/companies/${company.slug}`} target="_blank" style={{ color: "var(--text)", textDecoration: "none" }}>
                                                {company.name}
                                            </Link>
                                        </div>
                                        {company.website && (
                                            <div style={{ fontSize: "0.8125rem", color: "var(--primary)", marginTop: "0.25rem" }}>
                                                {company.website}
                                            </div>
                                        )}
                                    </td>
                                    <td style={{ ...tdStyle, color: "var(--text-muted)" }}>{company.industry || "Chưa cập nhật"}</td>
                                    <td style={{ ...tdStyle, fontWeight: 600 }}>{company._count.jobs}</td>
                                    <td style={tdStyle}>
                                        {company.verified ? (
                                            <span style={{ fontSize: "0.75rem", fontWeight: 700, padding: "0.375rem 0.75rem", borderRadius: "100px", background: "#DCFCE7", color: "#14532D" }}>
                                                Đã xác thực
                                            </span>
                                        ) : (
                                            <span style={{ fontSize: "0.75rem", fontWeight: 700, padding: "0.375rem 0.75rem", borderRadius: "100px", background: "#F1F5F9", color: "#475569" }}>
                                                Chưa xác thực
                                            </span>
                                        )}
                                    </td>
                                    <td style={{ ...tdStyle, textAlign: "right" }}>
                                        <CompanyVerifyButton id={company.id} verified={company.verified} />
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </DashboardLayout>
    );
}

const thStyle: React.CSSProperties = { padding: "1rem 1.25rem", textAlign: "left", fontSize: "0.8125rem", fontWeight: 700, color: "var(--text-muted)", textTransform: "uppercase" };
const tdStyle: React.CSSProperties = { padding: "1.25rem", verticalAlign: "middle" };
